  options = '[{"id":"A","text":"A semicolon. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"A colon. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"A comma. This choice completes the idea as a full sentence rather than a fragment.","is_correct":true,"explanation":"Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"No punctuation mark is needed. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'A comma is needed after “test-taking strategies” to separate the introductory phrase from the main clause. The introductory phrase introduces a list of ideas that are often overlooked in favor of test-taking strategies, and the main clause explains how this narrow focus can stifle creativity. Since the main clause is not a restatement of the introductory phrase, a comma is the most appropriate punctuation mark. The passage states that "Many people believe that a good education involves the ability to think critically, solve problems, and communicate effe…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: A comma. This choice completes the idea as a full sentence rather than a fragment.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
