  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"BOU","domain_id":"conventions","opensat_index":1174,"opensat_domain":"Standard English Conventions","opensat_raw_id":"f8423a9d","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.887Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
